## Security List

### Basic Security List

```hcl
resource "oci_core_security_list" "web_sl" {
  compartment_id = var.compartment_id
  vcn_id         = oci_core_vcn.vcn.id
  display_name   = "web-security-list"

  egress_security_rules {
    destination      = "0.0.0.0/0"
    protocol         = "all"
    description      = "Allow all egress"
  }

  ingress_security_rules {
    protocol  = "6"
    source    = "0.0.0.0/0"
    tcp_options {
      min = 443
      max = 443
    }
  }
}
```

### ICMP Example

```hcl
ingress_security_rules {
  protocol  = "1"
  source    = "10.0.0.0/16"
  icmp_options {
    type = 0
    code = 0
  }
}
```

## Resource Manager

### Stack

```hcl
resource "oci_resourcemanager_stack" "stack" {
  compartment_id = var.compartment_id
  display_name  = "my-stack"

  terraform_version = "1.6.x"

  config_source {
    zip_file_base64encoded = base64encode(file("terraform.zip"))
  }
}
```

### Plan Job

```hcl
resource "oci_resourcemanager_job" "plan" {
  stack_id = oci_resourcemanager_stack.stack.id
  operation = "PLAN"

  apply_job_plan_resolution {
    is_auto_approved = true
  }
}
```

### Apply Job

```hcl
resource "oci_resourcemanager_job" "apply" {
  stack_id = oci_resourcemanager_stack.stack.id
  operation = "APPLY"
}
```

### Destroy Job

```hcl
resource "oci_resourcemanager_job" "destroy" {
  stack_id = oci_resourcemanager_stack.stack.id
  operation = "DESTROY"
}
```

## Data Sources

### Get Compartment

```hcl
data "oci_identity_compartments" "compartments" {
  compartment_id            = var.tenancy_id
  compartment_id_in_subtree = true
}
```

### Get Image

```hcl
data "oci_core_images" "oracle_linux" {
  compartment_id          = var.compartment_id
  operating_system        = "Oracle Linux"
  operating_system_version = "8"
  shape                   = "VM.Standard2.1"
}
```

### Get Shape

```hcl
data "oci_core_shapes" "shapes" {
  compartment_id = var.compartment_id
  filter {
    name   = "shape"
    values = ["VM.Standard2.*"]
  }
}
```

### Get Subnet

```hcl
data "oci_core_subnet" "existing_subnet" {
  subnet_id = "ocid1.subnet.oc1..."
}
```

### Usage

```hcl
resource "oci_core_instance" "vm" {
  image_id = data.oci_core_images.oracle_linux.images[0].id
  # ...
}
```

## Container Instances

### Container Instance

```hcl
resource "oci_container_instance_container_instance" "container" {
  compartment_id = var.compartment_id
  display_name  = "my-container"
  availability_domain = "aaaa:US-ASHBURN-AD-1"

  shape = "CI.Standard.E4.Flex"

  shape_config {
    ocpus         = 1
    memory_in_gbs = 2
  }

  container_configurations {
    container_image_name = "nginx:latest"
    display_name       = "nginx"

    port_configurations {
      port = 80
    }

    environment_variables = {
      "ENV" = "prod"
    }
  }

  subnet_ids = [oci_core_subnet.public_subnet.id]
}
```

### Multiple Containers

```hcl
container_configurations {
  # Container 1
  {
    display_name = "web"
    container_image_name = "nginx"
  },
  # Container 2
  {
    display_name = "app"
    container_image_name = "myapp:latest"
  }
}
```

## Service Gateway

```hcl
resource "oci_core_service_gateway" "sgw" {
  compartment_id = var.compartment_id
  vcn_id         = oci_core_vcn.vcn.id
  display_name   = "service-gateway"
  services {
    service_id = data.oci_core_services.orcl_services.services[0].id
  }
}
```

### Route Table

```hcl
resource "oci_core_route_table" "service_rt" {
  compartment_id = var.compartment_id
  vcn_id         = oci_core_vcn.vcn.id

  route_rules {
    destination       = "all-oics-in-oracle-services-network"
    destination_type  = "SERVICE_CIDR_BLOCK"
    network_entity_id = oci_core_service_gateway.sgw.id
  }
}
```

### Data Source

```hcl
data "oci_core_services" "orcl_services" {
  filter {
    name   = "name"
    values = ["OCI Streaming"]
  }
}

## Provider Versioning

### Version Constraint

```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = ">= 5.0.0, < 6.0.0"
    }
  }
}
```

### Version Operators

| Operator | Meaning |
|----------|--------|
| = 1.0.0 | Exactly version |
| >= 1.0.0 | Greater or equal |
| <= 1.0.0 | Less or equal |
| ~> 1.0 | 1.x range |
| >= 1.0.0, < 2.0.0 | Range |

### Upgrade Provider

```bash
# Upgrade
terraform init -upgrade

# Pin specific version
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "5.26.0"
    }
  }
}
```

### Best Practice

- Pin version em production
- Test before upgrade

## for_each e count

### count

```hcl
variable "subnets" {
  default = [
    { name = "web", cidr = "10.0.1.0/24" },
    { name = "app", cidr = "10.0.2.0/24" },
    { name = "db",  cidr = "10.0.3.0/24" }
  ]
}

resource "oci_core_subnet" "subnets" {
  count          = length(var.subnets)
  compartment_id = var.compartment_id
  vcn_id         = oci_core_vcn.vcn.id
  cidr_block     = var.subnets[count.index].cidr
  display_name   = var.subnets[count.index].name
}
```

### for_each

```hcl
variable "users" {
  default = {
    "alice" = { email = "alice@example.com", group = "admins" },
    "bob"   = { email = "bob@example.com", group = "developers" }
  }
}

resource "oci_identity_user" "users" {
  for_each = var.users
  name     = each.key
  email    = each.value.email
}
```

### Recommendation

- for_each e mais legivel
- Mantem stability

## Object Storage Bucket

```hcl
resource "oci_object_storage_bucket" "bucket" {
  compartment_id = var.compartment_id
  namespace      = var.namespace
  name          = "my-bucket"
  storage_tier  = "Standard"
  versioning    = "Enabled"
}
```

### Lifecycle Policy

```hcl
resource "oci_object_storage_bucket" "tiered" {
  compartment_id = var.compartment_id
  namespace      = var.namespace
  name          = "tiered-bucket"

  lifecycle_policy {
    items {
      target     = "ARCHIVE"
      days_after_modification_greater_than = 30
    }
  }
}
```

### Pre-Authenticated Request

```hcl
resource "oci_object_storage_preauthrequest" "par" {
  bucket    = oci_object_storage_bucket.bucket.name
  namespace = var.namespace
  name     = "my-par"
  object   = "data/file.csv"
  time_expires = "2025-12-31T00:00:00Z"
}
